urlset:
{{ range (where .Data.Pages "Kind" "not in" (slice "taxonomy" "term")) }}
  {{- if .Permalink -}}

  {{ .Permalink }}
  {{ if not .Lastmod.IsZero }}
  {{ safeHTML ( .Lastmod.Format "2006-01-02T15:04:05-07:00" ) }}
  {{ end }}
  {{ with .Sitemap.ChangeFreq }}
  {{ . }}
  {{ else }}
  {{ if .IsPage }}monthly{{ else }}weekly{{ end }}
  {{ end }}
  {{ with .Sitemap.Priority }}
  {{ . }}
  {{ else }}
  {{ if .IsHome }}1.0{{ else if .IsPage }}0.8{{ else }}0.5{{ end }}
  {{ end }}
  {{ if .IsTranslated }}
  {{ range .AllTranslations }}

  {{ end }}

  {{ end }}

  {{- end -}}
{{ end }}
